// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract Counter {
    uint256 public count;

    function increment() external {
        count++;
    }

    function get() external view returns (uint256) {
        return count;
    }
}

contract CloneFactory {
    address public implementation;
    event Cloned(address indexed proxy);

    constructor(address _implementation) {
        implementation = _implementation;
    }

    function clone() external returns (address instance) {
        address impl = implementation;
        assembly {
            let ptr := mload(0x40)
            mstore(ptr, [[SLOT eip1167_prefix]])
            mstore(add(ptr, 0x14), [[SLOT impl_shift]])
            mstore(add(ptr, 0x28), [[SLOT eip1167_suffix]])
            instance := [[SLOT create_call]]
        }
        require(instance != address(0), "Clone failed");
        emit Cloned(instance);
    }
}
